changeSet.sql:
ALTER TABLE transactions DROP CONSTRAINT IF EXISTS fk_tx_session;
ALTER TABLE transactions ALTER COLUMN session_id DROP NOT NULL;
ALTER TABLE transactions ADD CONSTRAINT fk_tx_session FOREIGN KEY (session_id) REFERENCES sessions(id);

ALTER TABLE transactions DROP CONSTRAINT IF EXISTS fk_tx_user;
ALTER TABLE transactions ALTER COLUMN processed_by DROP NOT NULL;
ALTER TABLE transactions ADD CONSTRAINT fk_tx_user FOREIGN KEY (processed_by) REFERENCES users(id);
